local function notify(t,c,d) Library:Notify({Title=t or"Notification",Description=c or"",Time=d or 5}) end
local function sendHubLoadedMessage() local m=" Owner Version | GGOG Script 0.0.4 Alpha loaded. " local s=false pcall(function() local ce=ReplicatedStorage:FindFirstChild("DefaultChatSystemChatEvents") if ce then local say=ce:FindFirstChild("SayMessageRequest") if say then say:FireServer(m,"All") s=true end end end) if not s then pcall(function() StarterGui:SetCore("ChatMakeSystemMessage",{Text=m,Color=Color3.fromRGB(255,170,0),Font=Enum.Font.SourceSansBold,FontSize=Enum.FontSize.Size18}) end) end end
task.spawn(function() task.wait(1) sendHubLoadedMessage() end)
local paintPartsBackup={} local paintConnections={}
local function deleteAllPaintParts() for _,o in ipairs(Workspace:GetDescendants()) do if o:IsA("BasePart") and o.Name=="PaintPlayerPart" then local c=o:Clone() c.Archivable=true paintPartsBackup[o:GetDebugId()]={clone=c,parent=o.Parent} o:Destroy() end end end
local function restorePaintParts() for _,d in pairs(paintPartsBackup) do if d.clone and d.parent then d.clone.Parent=d.parent end end paintPartsBackup={} end
local function watchNewPaintParts() table.insert(paintConnections,Workspace.DescendantAdded:Connect(function(o) if o:IsA("BasePart") and o.Name=="PaintPlayerPart" then task.defer(function() if o and o.Parent then local c=o:Clone() c.Archivable=true paintPartsBackup[o:GetDebugId()]={clone=c,parent=o.Parent} o:Destroy() end end) end end)) end
local function disconnectWatchers() for _,c in ipairs(paintConnections) do if c.Connected then c:Disconnect() end end paintConnections={} end
local function setTouchQuery(s) local ch=Workspace:FindFirstChild(Player.Name) if not ch then return end for _,v in ipairs(ch:GetChildren()) do if v:IsA("Part") or v:IsA("BasePart") then v.CanTouch=s v.CanQuery=s end end end
local antiGucciConnection local safePosition local restoreFrames=0
local function spawnBlobman() pcall(function() ReplicatedStorage.MenuToys.SpawnToyRemoteFunction:InvokeServer("CreatureBlobman",CFrame.new(0,5000000,0),Vector3.new(0,60,0)) end) local f=Workspace:WaitForChild(Player.Name.."SpawnedInToys",5) if f and f:FindFirstChild("CreatureBlobman") then local b=f.CreatureBlobman if b:FindFirstChild("Head") then b.Head.CFrame=CFrame.new(0,50000,0) b.Head.Anchored=true end notify("Success","Blobman Spawned!",3) end end
local function startAntiGucci() local ch=Player.Character or Player.CharacterAdded:Wait() local hum=ch:WaitForChild("Humanoid") local rp=ch:WaitForChild("HumanoidRootPart") safePosition=rp.Position local f=Workspace:FindFirstChild(Player.Name.."SpawnedInToys") local bl=f and f:FindFirstChild("CreatureBlobman") local se=bl and bl:FindFirstChild("VehicleSeat") if not bl then spawnBlobman() task.wait(1) f=Workspace:FindFirstChild(Player.Name.."SpawnedInToys") bl=f and f:FindFirstChild("CreatureBlobman") se=bl and bl:FindFirstChild("VehicleSeat") end if se and se:IsA("VehicleSeat") then rp.CFrame=se.CFrame+Vector3.new(0,2,0) se:Sit(hum) end hum:GetPropertyChangedSignal("Jump"):Connect(function() if hum.Jump and hum.Sit then restoreFrames=15 safePosition=rp.Position end end) if antiGucciConnection then antiGucciConnection:Disconnect() end antiGucciConnection=R.Heartbeat:Connect(function() if not rp or not hum then return end ReplicatedStorage.CharacterEvents.RagdollRemote:FireServer(rp,0) if restoreFrames>0 then rp.CFrame=CFrame.new(safePosition) restoreFrames=restoreFrames-1 end end) task.spawn(function() while hum.Sit do task.wait(1) end task.wait(0.5) rp.CFrame=CFrame.new(safePosition) end) end
local function stopAntiGucci() if antiGucciConnection then antiGucciConnection:Disconnect() antiGucciConnection=nil end local bf=Workspace:FindFirstChild(Player.Name.."SpawnedInToys") if bf and bf:FindFirstChild("CreatureBlobman") then bf.CreatureBlobman:Destroy() end end
local antiGucciConnectionTrain local safePositionTrain local restoreFramesTrain=0
local function startAntiGucciTrain() local ch=Player.Character or Player.CharacterAdded:Wait() local hum=ch:WaitForChild("Humanoid") local rp=ch:WaitForChild("HumanoidRootPart") safePositionTrain=rp.Position local f=workspace.Map.AlwaysHereTweenedObjects local tr=f and f:FindFirstChild("Train") local se if tr then for _,d in ipairs(tr:GetDescendants()) do if d:IsA("Seat") then se=d break end end end if se then rp.CFrame=se.CFrame+Vector3.new(0,2,0) se:Sit(hum) end hum:GetPropertyChangedSignal("Jump"):Connect(function() if hum.Jump and hum.Sit then restoreFramesTrain=15 safePositionTrain=rp.Position end end) if antiGucciConnectionTrain then antiGucciConnectionTrain:Disconnect() end antiGucciConnectionTrain=R.Heartbeat:Connect(function() if not rp or not hum then return end ReplicatedStorage.CharacterEvents.RagdollRemote:FireServer(rp,0) if restoreFramesTrain>0 then rp.CFrame=CFrame.new(safePositionTrain) restoreFramesTrain=restoreFramesTrain-1 end end) task.spawn(function() while hum.Sit do task.wait(1) end task.wait(0.5) rp.CFrame=CFrame.new(safePositionTrain) end) end
local function stopAntiGucciTrain() if antiGucciConnectionTrain then antiGucciConnectionTrain:Disconnect() antiGucciConnectionTrain=nil end end
local DefenseGroup=Tabs.Defense:AddLeftGroupbox("Defense Main") local DefenseExtra=Tabs.Defense:AddRightGroupbox("Extra Defense")
local antiGrabExplosionConn,antiGrabHeldConn,antiGrabStruggleConn,antiGrabHumConn,antiGrabAnchorConn local antiGrabRootCF,antiGrabRootPos,antiGrabHardFreeze=nil,nil,false
