DefenseGroup:AddToggle("AntiGrabObsidian",{Text="Anti Grab",Default=false,Callback=function(V) local RS2=game:GetService("RunService") local RS3=game:GetService("ReplicatedStorage") local lp=game:GetService("Players").LocalPlayer local St=RS3:FindFirstChild("CharacterEvents") and RS3.CharacterEvents:FindFirstChild("Struggle") if V then if autoStruggleConn then autoStruggleConn:Disconnect() end autoStruggleConn=RS2.Heartbeat:Connect(function() local c=lp.Character if c and c:FindFirstChild("Head") then local hd=c.Head if hd:FindFirstChild("PartOwner") then task.spawn(function() if St then St:FireServer(lp) end pcall(function() RS3.GameCorrectionEvents.StopAllVelocity:FireServer() end) for _,p in pairs(c:GetChildren()) do if p:IsA("BasePart") then p.Anchored=true end end local ih=lp:FindFirstChild("IsHeld") while ih and ih.Value do task.wait() end for _,p in pairs(c:GetChildren()) do if p:IsA("BasePart") then p.Anchored=false end end end) end end end) else if autoStruggleConn then autoStruggleConn:Disconnect() autoStruggleConn=nil end local c=lp.Character if c then for _,p in pairs(c:GetChildren()) do if p:IsA("BasePart") then p.Anchored=false end end end end end})
local antiBlob1T=false local function antiBlob1F() antiBlob1T=true workspace.DescendantAdded:Connect(function(t) if t.Name=="CreatureBlobman" and antiBlob1T then t.LeftDetector:Destroy() t.RightDetector:Destroy() end end) end
DefenseGroup:AddToggle("AntiBlobmanToggle",{Text="Anti Blobman",Default=false,Callback=function(on) if on then antiBlob1F() else antiBlob1T=false end end})
local antiExplodeT=false local function antiExplodeF() antiExplodeT=true local ch=Player.Character if not ch then return end local h=ch:WaitForChild("HumanoidRootPart") workspace.ChildAdded:Connect(function(m) if m.Name=="Part" and antiExplodeT then local mg=(m.Position-h.Position).Magnitude if mg<=20 then h.Anchored=true wait(0.01) while ch["Right Arm"].RagdollLimbPart.CanCollide do wait(0.001) end h.Anchored=false end end end) end
DefenseGroup:AddToggle("AntiExplosionToggle",{Text="Anti Explosion",Default=false,Callback=function(on) if on then antiExplodeF() else antiExplodeT=false end end})
local hookBurnConn local function hookBurn(ch) local hum=ch:WaitForChild("Humanoid") local h=ch:WaitForChild("HumanoidRootPart") ch.PrimaryPart=h if hookBurnConn then hookBurnConn:Disconnect() end hookBurnConn=hum.FireDebounce.Changed:Connect(function(ib) if ib then local me=ch local old=h.CFrame local pl=workspace:FindFirstChild("Plots") if pl and pl:FindFirstChild("Plot2") then local p2=pl.Plot2 local ba=p2:FindFirstChild("Barrier") local pb=ba and ba:FindFirstChild("PlotBarrier") if pb and pb:IsA("BasePart") then local sf=pb.CFrame*CFrame.new(0,6,0) me:SetPrimaryPartCFrame(sf) task.wait(0.3) local fp=me:FindFirstChild("FirePlayerPart",true) if fp then for _,o in ipairs(fp:GetChildren()) do if o:IsA("Sound") then o:Stop() end if o:IsA("Light") or o:IsA("ParticleEmitter") then o.Enabled=false end end if fp:FindFirstChild("CanBurn") then fp.CanBurn.Value=false end if hum:FindFirstChild("FireDebounce") then hum.FireDebounce.Value=false end end task.wait(0.6) if me and me.PrimaryPart then me:SetPrimaryPartCFrame(old) end end end end end) end
DefenseGroup:AddToggle("AntiBurnToggle",{Text="Anti Burn",Default=false,Callback=function(on) if on then hookBurn(Player.Character) elseif hookBurnConn then hookBurnConn:Disconnect() end end})
local antiVoidConn local VT=-50 local SH=100
DefenseGroup:AddToggle("AntiVoidToggle",{Text="Anti Void",Default=false,Callback=function(on) if on then if antiVoidConn then antiVoidConn:Disconnect() end antiVoidConn=R.Heartbeat:Connect(function() local c=Player.Character if c and c.PrimaryPart then local p=c.PrimaryPart.Position if p.Y<VT then c:SetPrimaryPartCFrame(CFrame.new(Vector3.new(p.X,p.Y+SH,p.Z))) c.PrimaryPart.AssemblyLinearVelocity=Vector3.zero end end end) else if antiVoidConn then antiVoidConn:Disconnect() antiVoidConn=nil end end end})
