local createGrabLineCopy,extendGrabLineCopy local gf=ReplicatedStorage:FindFirstChild("GrabEvents") if gf then local oc=gf:FindFirstChild("CreateGrabLine") local oe=gf:FindFirstChild("ExtendGrabLine") if oc then createGrabLineCopy=oc:Clone() end if oe then extendGrabLineCopy=oe:Clone() end end
DefenseGroup:AddToggle("AntiLagToggle",{Text="Anti Lag",Default=false,Callback=function(V) if V then local g=ReplicatedStorage:FindFirstChild("GrabEvents") if g then local c=g:FindFirstChild("CreateGrabLine") local e=g:FindFirstChild("ExtendGrabLine") if c and c:IsA("RemoteEvent") then c:Destroy() end if e and e:IsA("RemoteEvent") then e:Destroy() end end for _,v in ipairs(workspace:GetDescendants()) do if v:IsA("Beam") or v.Name:lower():find("line") then v:Destroy() end end else local g=ReplicatedStorage:FindFirstChild("GrabEvents") if g then if createGrabLineCopy and not g:FindFirstChild("CreateGrabLine") then createGrabLineCopy:Clone().Parent=g end if extendGrabLineCopy and not g:FindFirstChild("ExtendGrabLine") then extendGrabLineCopy:Clone().Parent=g end end end end})
DefenseExtra:AddToggle("PaintDeleteToggle",{Text="Anti Paint",Default=false,Callback=function(s) if s then deleteAllPaintParts() watchNewPaintParts() setTouchQuery(false) else restorePaintParts() disconnectWatchers() setTouchQuery(true) end end})
local autoGucciActive=false
DefenseExtra:AddToggle("AutoGucciToggle",{Text="Anti Gucci (Blobman)",Default=false,Callback=function(V) autoGucciActive=V if V then startAntiGucci() notify("system","auto gucci active",3) task.spawn(function() while autoGucciActive do local tf=Workspace:FindFirstChild(Player.Name.."SpawnedInToys") if not(tf and tf:FindFirstChild("CreatureBlobman")) then stopAntiGucci() spawnBlobman() notify("System","blobman lost",3) local r=0 repeat task.wait(0.2) r=r+1 tf=Workspace:FindFirstChild(Player.Name.."SpawnedInToys") until(tf and tf:FindFirstChild("CreatureBlobman")) or r>25 or not autoGucciActive if autoGucciActive and tf and tf:FindFirstChild("CreatureBlobman") then startAntiGucci() notify("System","blobman restored.",3) end end task.wait(0.5) end end) else autoGucciActive=false stopAntiGucci() notify("System","auto gucci disabled.",3) end end})
local autoGucciActiveTrain=false
DefenseExtra:AddToggle("AutoGucciToggleTrain",{Text="Anti Gucci (Train)",Default=false,Callback=function(V) autoGucciActiveTrain=V if V then startAntiGucciTrain() notify("system","Gucci active",3) task.spawn(function() while autoGucciActiveTrain do local tf=workspace.Map.AlwaysHereTweenedObjects if not(tf and tf:FindFirstChild("Train")) then stopAntiGucciTrain() notify("System","Train lost",3) local r=0 repeat task.wait(0.2) r=r+1 tf=workspace.Map.AlwaysHereTweenedObjects until(tf and tf:FindFirstChild("Train")) or r>25 or not autoGucciActiveTrain if autoGucciActiveTrain and tf and tf:FindFirstChild("Train") then startAntiGucciTrain() notify("System","Train restored.",3) end end task.wait(0.5) end end) else autoGucciActiveTrain=false stopAntiGucciTrain() notify("System","Gucci disabled.",3) end end})
local ToyList={["Coconut"]="FoodCoconut",["Banana"]="FoodBanana",["Fries"]="FoodFrenchFries",["MeatStick"]="FoodMeatStick",["Poop"]="PoopPile",["Donut"]="FoodDonut",["Cake"]="FoodCakePink",["Burger"]="FoodHamburger",["Pizza"]="FoodPizzaCheese",["Hotdog"]="FoodHotdog",["Mushroom"]="FoodMushroomPoison",["Banjo"]="InstrumentGuitarBanjo",["Violin"]="InstrumentGuitarViolin",["Ukulele"]="InstrumentGuitarUkulele",["Sax"]="InstrumentWoodwindSaxophone",["Vuvuzela"]="InstrumentBrassVuvuzela",["Bongos"]="InstrumentDrumBongos",["Mic"]="InstrumentVoiceMicrophone",["Pepperoni"]="FoodPizzaPepperoni",["Piano"]="InstrumentPianoMelodica",["Bread"]="FoodBread",["Egg"]="FoodDippyEgg",["Mayo"]="FoodMayonnaise",["WhiteMug"]="CupMugWhite",["Ocarina"]="InstrumentWoodwindOcarina",["SparklePoop"]="PoopPileSparkle",["BrownMug"]="CupMugBrown",["Trumpet"]="InstrumentBrassTrumpet",["Snare"]="InstrumentDrumSnare"}
