DefenseExtra:AddToggle("AntiInputLag",{Text="Anti Input Lag",Default=false,Callback=function(V) _G.AntiInputLag=V if V then task.spawn(function() local p=Players.LocalPlayer local c=p.Character or p.CharacterAdded:Wait() local h=c:WaitForChild("HumanoidRootPart") local SR=ReplicatedStorage:WaitForChild("MenuToys"):WaitForChild("SpawnToyRemoteFunction") while _G.AntiInputLag do local tf=Workspace:FindFirstChild(p.Name.."SpawnedInToys") if not tf then task.wait(0.1) continue end local t=tf:FindFirstChild(SelectedToy) if not t then pcall(function() SR:InvokeServer(SelectedToy,h.CFrame*CFrame.new(0,5,0),Vector3.zero) end) local t0=tick() repeat RunService.Heartbeat:Wait() tf=Workspace:FindFirstChild(p.Name.."SpawnedInToys") t=tf and tf:FindFirstChild(SelectedToy) until t or tick()-t0>1 or not _G.AntiInputLag end if t and t.Parent then local hp=t:FindFirstChild("HoldPart") if hp then local hv=hp:FindFirstChild("HoldingPlayer") hv=hv and hv.Value if hv and hv~=p then pcall(function() hp.DropItemRemoteFunction:InvokeServer(t,h.CFrame*CFrame.new(0,2000,0),Vector3.zero) end) t:Destroy() else pcall(function() hp.HoldItemRemoteFunction:InvokeServer(t,c) end) task.wait(0.05) pcall(function() hp.DropItemRemoteFunction:InvokeServer(t,h.CFrame*CFrame.new(0,2000,0),Vector3.zero) end) task.wait(0.01) end end end RunService.Heartbeat:Wait() end end) end end})
local tpActive=false
DefenseExtra:AddToggle("ShurikenAntiKick",{Text="Anti Kick",Default=false,Callback=function(V) _G.ShurikenAntiKick=V local function ClearKunai() local p=game.Players.LocalPlayer local inv=workspace:FindFirstChild(p.Name.."SpawnedInToys") local dr=game.ReplicatedStorage:FindFirstChild("MenuToys") and game.ReplicatedStorage.MenuToys:FindFirstChild("DestroyToy") if inv and dr then for _,v in pairs(inv:GetChildren()) do if v.Name=="AntiKick" or v.Name=="NinjaShuriken" then pcall(function() dr:FireServer(v) end) end end end end if V then task.spawn(function() local p=game.Players.LocalPlayer local so=ReplicatedStorage:WaitForChild("GrabEvents"):WaitForChild("SetNetworkOwner") local se=ReplicatedStorage:WaitForChild("PlayerEvents"):WaitForChild("StickyPartEvent") local sr=ReplicatedStorage.MenuToys.SpawnToyRemoteFunction local dr=ReplicatedStorage:WaitForChild("MenuToys"):WaitForChild("DestroyToy") local cs=p:WaitForChild("CanSpawnToy") local function gH() if p.Character and p.Character:FindFirstChild("HumanoidRootPart") then return p.Character.HumanoidRootPart else return p.CharacterAdded:Wait():WaitForChild("HumanoidRootPart") end end local function CFH() if not workspace.PlotItems.PlayersInPlots:FindFirstChild(p.Name) then return false end for _,v in pairs(workspace.Plots:GetChildren()) do local sg=v:FindFirstChild("PlotSign") local ow=sg and sg:FindFirstChild("ThisPlotsOwners") if ow then for _,b in pairs(ow:GetChildren()) do if b.Value==p.Name then local f=workspace.PlotItems:FindFirstChild(v.Name) if f then return true,f end end end end end return false end local function SK(k) if not k or not k:FindFirstChild("StickyPart") then return end local ch=gH() if not ch then return end if k:FindFirstChild("SoundPart") then if not k.SoundPart:FindFirstChild("PartOwner") or k.SoundPart.PartOwner.Value~=p.Name then so:FireServer(k.SoundPart,k.SoundPart.CFrame) end end local fp=ch:FindFirstChild("FirePlayerPart") or ch:WaitForChild("FirePlayerPart",5) if fp then se:FireServer(k.StickyPart,fp,CFrame.new(0,0,0)*CFrame.Angles(0,math.rad(90),math.rad(90))) end for _,o in pairs(k:GetChildren()) do if o.Name=="Pyramid" then o.CanTouch=false o.CanCollide=false o.CanQuery=false o.Transparency=0 if not o:FindFirstChild("Highlight") then local h=Instance.new("Highlight",o) h.FillColor=Color3.fromRGB(0,0,0) end elseif o.Name=="Main" then o.CanTouch=false o.CanCollide=false o.CanQuery=false o.Transparency=0 if not o:FindFirstChild("Highlight") then local h=Instance.new("Highlight",o) h.FillColor=Color3.fromRGB(255,255,255) end elseif o:IsA("BasePart") then o.CanTouch=false o.CanCollide=false o.CanQuery=false o.Transparency=1 end end end local function ST(n) local t=tick() while not cs.Value do if not _G.ShurikenAntiKick or tick()-t>5 then return nil end task.wait(0.1) end local ch=gH() if ch then task.spawn(function() pcall(function() sr:InvokeServer(n,ch.CFrame*CFrame.new(0,12,20),Vector3.new(0,0,0)) end) end) end local bk,hs=CFH() local inv=workspace:FindFirstChild(p.Name.."SpawnedInToys") if bk and hs then return hs:WaitForChild(n,2) elseif not workspace.PlotItems.PlayersInPlots:FindFirstChild(p.Name) and inv then return inv:WaitForChild(n,2) end return nil end while _G.ShurikenAntiKick do task.wait(0.005) if not p.Character or not p.Character:FindFirstChild("Humanoid") or p.Character.Humanoid.Health<=0 then continue end local inv=workspace:FindFirstChild(p.Name.."SpawnedInToys") local k=inv and inv:FindFirstChild("NinjaShuriken") if workspace.PlotItems.PlayersInPlots:FindFirstChild(p.Name) then local bk,hs=CFH() if bk and hs and workspace.Plots:FindFirstChild(hs.Name) then local sg=workspace.Plots[hs.Name]:FindFirstChild("PlotSign") if sg and sg.ThisPlotsOwners.Value.TimeRemainingNum.Value>89 then k=ST("NinjaShuriken") if k==nil then continue end k.Name="AntiKick" SK(k) end end end if not k then if workspace.PlotItems.PlayersInPlots:FindFirstChild(p.Name) then continue end k=ST("NinjaShuriken") if k==nil then continue end k.Name="AntiKick" if not k then continue end end repeat if k and k:FindFirstChild("StickyPart") and k.StickyPart.CanTouch==true then SK(k) k.Name="AntiKick" end task.wait(0.3) until not k or not _G.ShurikenAntiKick or not k:FindFirstChild("StickyPart") or k.StickyPart.CanTouch==false or not p.Character or not p.Character:FindFirstChild("HumanoidRootPart") or(p.Character.HumanoidRootPart.Position-k.StickyPart.Position).Magnitude>=20 if not k or not k:FindFirstChild("StickyPart") or not p.Character or not p.Character:FindFirstChild("HumanoidRootPart") or(p.Character.HumanoidRootPart.Position-k.StickyPart.Position).Magnitude>=20 then ClearKunai() end pcall(function() repeat task.wait(0.05) until not _G.ShurikenAntiKick or not p.Character or not p.Character:FindFirstChild("Humanoid") or not k or not k:FindFirstChild("StickyPart") or not k.StickyPart:FindFirstChild("StickyWeld") or not k.StickyPart.StickyWeld.Part1 if not k or not k:FindFirstChild("StickyPart") or(p.Character and p.Character:FindFirstChild("Humanoid") and p.Character.Humanoid.Health<=0) or not k["StickyPart"]:FindFirstChild("StickyWeld").Part1 then ClearKunai() end end) end end) else _G.ShurikenAntiKick=false ClearKunai() end end})
DefenseExtra:AddToggle("LoopTP",{Text="Loop TP",Default=false,Callback=function(V) tpActive=V local c=Player.Character or Player.CharacterAdded:Wait() local h=c:WaitForChild("HumanoidRootPart") local hm=c:FindFirstChildOfClass("Humanoid") if V then if hm then hm.PlatformStand=true end task.spawn(function() while tpActive and h do h.CFrame=CFrame.new(math.random(-500,500),math.random(30,480),math.random(-500,500)) task.wait(0.03) end end) else if hm then hm.PlatformStand=false end end end})
