TargetGroup:AddDropdown("KickPlayerDropdown",{Values=getPlayerList(),Default=1,Multi=false,Text="select player for kick",Callback=function(V) selectedKickPlayer=getPlayerFromSelection(V) end})
TargetGroup:AddButton({Text="refresh player list",Func=function() Options.KickPlayerDropdown:SetValues(getPlayerList()) Options.KickPlayerDropdown:SetValue(nil) selectedKickPlayer=nil end})
TargetGroup:AddToggle("LoopKickGrabToggle1",{Text="Kick (spam grab)",Default=false,Callback=function(on) kickLoopEnabled=on if not on then return end task.spawn(function() local GE=RS:WaitForChild("GrabEvents") local mc=Player.Character local mr=mc and mc:FindFirstChild("HumanoidRootPart") if not mr then Toggles.LoopKickGrabToggle1:SetValue(false) return end local sp=mr.CFrame local dg=false local gt=0 while kickLoopEnabled do local tg=selectedKickPlayer if not tg or not tg.Parent then break end mc=Player.Character mr=mc and mc:FindFirstChild("HumanoidRootPart") if not mr then break end local tc=tg.Character local tr=tc and tc:FindFirstChild("HumanoidRootPart") local th=tc and tc:FindFirstChild("Humanoid") if tr and th and th.Health>0 then tr.AssemblyLinearVelocity=Vector3.zero tr.AssemblyAngularVelocity=Vector3.zero tr.Velocity=Vector3.zero if not dg then mr.CFrame=tr.CFrame mr.Velocity=Vector3.zero pcall(function() th.PlatformStand=true th.Sit=true GE.SetNetworkOwner:FireServer(tr,mr.CFrame) GE.CreateGrabLine:FireServer(tr,Vector3.zero,tr.Position,false) end) if gt==0 then gt=tick() end if tick()-gt>0.35 then dg=true gt=0 end else mr.CFrame=sp mr.Velocity=Vector3.zero local lp=sp*CFrame.new(0,17,0) tr.CFrame=lp tr.Velocity=Vector3.zero tr.RotVelocity=Vector3.zero pcall(function() th.PlatformStand=true th.Sit=false GE.SetNetworkOwner:FireServer(tr,lp) GE.DestroyGrabLine:FireServer(tr) GE.CreateGrabLine:FireServer(tr,Vector3.zero,tr.Position,false) end) end else dg=false gt=0 end RunService.Heartbeat:Wait() end if mr then mr.CFrame=sp mr.Velocity=Vector3.zero end kickLoopEnabled=false Toggles.LoopKickGrabToggle1:SetValue(false) end) end})
TargetGroup:AddToggle("RagdollSnowballKick",{Text="Ragdoll Snowball",Default=false,Callback=function(on) local SR=RS:WaitForChild("MenuToys"):WaitForChild("SpawnToyRemoteFunction") local re=on task.spawn(function() while re do local tg=selectedKickPlayer if not tg or not tg.Parent then RunService.Heartbeat:Wait() continue end local tc=tg.Character local ts=tc and(tc:FindFirstChild("UpperTorso") or tc:FindFirstChild("Torso")) if not ts then RunService.Heartbeat:Wait() continue end pcall(function() SR:InvokeServer("BallSnowball",ts.CFrame*CFrame.new(Vector3.new(math.random(-30,30)/100,math.random(-30,30)/100,math.random(-30,30)/100)),Vector3.zero) end) local f=Workspace:FindFirstChild(Player.Name.."SpawnedInToys") if f then for _,s in pairs(f:GetChildren()) do if s.Name=="BallSnowball" and s.Parent then local p=s.PrimaryPart or s:FindFirstChildWhichIsA("BasePart") if p then p.CFrame=ts.CFrame*CFrame.new(Vector3.new(math.random(-30,30)/100,math.random(-30,30)/100,math.random(-30,30)/100)) p.AssemblyLinearVelocity=Vector3.zero p.AssemblyAngularVelocity=Vector3.zero end end end end RunService.Heartbeat:Wait() end end) end})
TargetGroup:AddToggle("LoopKickGrabToggle2",{Text="Kick (ragdoll grab)",Default=false,Callback=function(on) kickLoopEnabled=on if not on then return end task.spawn(function() local GE=RS:WaitForChild("GrabEvents") local C=Player.Character or Player.CharacterAdded:Wait() local mr=C:FindFirstChild("HumanoidRootPart") if not mr then Toggles.LoopKickGrabToggle2:SetValue(false) return end local sp=mr.CFrame local dg=false local gs=0 while kickLoopEnabled do local tg=selectedKickPlayer if not tg or not tg.Parent then break end local tc=tg.Character local tr=tc and tc:FindFirstChild("HumanoidRootPart") local th=tc and tc:FindFirstChild("Humanoid") if tr and th and th.Health>0 then tr.AssemblyLinearVelocity=Vector3.zero tr.AssemblyAngularVelocity=Vector3.zero tr.Velocity=Vector3.zero if not dg then mr.CFrame=tr.CFrame pcall(function() th.PlatformStand=true th.Sit=true GE.SetNetworkOwner:FireServer(tr,mr.CFrame) GE.CreateGrabLine:FireServer(tr,Vector3.zero,tr.Position,false) end) if gs==0 then gs=tick() end if tick()-gs>0.15 then dg=true gs=0 mr.CFrame=sp end else local lc=CFrame.new(sp.Position+Vector3.new(0,7,0))*CFrame.Angles(math.rad(math.random(-180,180)),math.rad(math.random(-180,180)),math.rad(math.random(-180,180))) tr.CFrame=tr.CFrame:Lerp(lc,0.2) tr.Velocity=Vector3.zero tr.RotVelocity=Vector3.zero pcall(function() th.PlatformStand=true th.Sit=false GE.SetNetworkOwner:FireServer(tr,tr.CFrame) GE.DestroyGrabLine:FireServer(tr) GE.CreateGrabLine:FireServer(tr,Vector3.zero,tr.Position,false) end) end else dg=false gs=0 end RunService.Heartbeat:Wait() end if mr then mr.CFrame=sp mr.Velocity=Vector3.zero end kickLoopEnabled=false Toggles.LoopKickGrabToggle2:SetValue(false) end) end})
local function IsRagdolled(h) local r=h and h:FindFirstChild("Ragdolled") return r~=nil and r.Value==true end
TargetGroup:AddToggle("GrabTrollToggle",{Text="Grab Troll (spam grab)",Default=false,Callback=function(on) kickLoopEnabled=on if not on then return end task.spawn(function() local GE=RS:WaitForChild("GrabEvents") local mc=Player.Character local mr=mc and mc:FindFirstChild("HumanoidRootPart") if not mr then Toggles.GrabTrollToggle:SetValue(false) return end local sp=mr.CFrame local dg=false local gt=0 while kickLoopEnabled do local tg=selectedKickPlayer if not tg or not tg.Parent then break end mc=Player.Character mr=mc and mc:FindFirstChild("HumanoidRootPart") if not mr then break end local tc=tg.Character local tr=tc and tc:FindFirstChild("HumanoidRootPart") local th=tc and tc:FindFirstChild("Humanoid") if tr and th and th.Health>0 then tr.AssemblyLinearVelocity=Vector3.zero tr.AssemblyAngularVelocity=Vector3.zero tr.Velocity=Vector3.zero if not dg then mr.CFrame=tr.CFrame mr.Velocity=Vector3.zero pcall(function() th.PlatformStand=true th.Sit=true GE.SetNetworkOwner:FireServer(tr,mr.CFrame) GE.CreateGrabLine:FireServer(tr,Vector3.zero,tr.Position,false) end) if gt==0 then gt=tick() elseif tick()-gt>0.35 then dg=true gt=0 end else if not IsRagdolled(th) then dg=false gt=0 pcall(function() GE.DestroyGrabLine:FireServer(tr) end) RunService.Heartbeat:Wait() continue end mr.CFrame=sp mr.Velocity=Vector3.zero local lp=sp*CFrame.new(0,17,0) tr.CFrame=lp tr.Velocity=Vector3.zero tr.RotVelocity=Vector3.zero pcall(function() th.PlatformStand=true th.Sit=false GE.SetNetworkOwner:FireServer(tr,lp) GE.DestroyGrabLine:FireServer(tr) GE.CreateGrabLine:FireServer(tr,Vector3.zero,tr.Position,false) end) end else dg=false gt=0 end RunService.Heartbeat:Wait() end if mr then mr.CFrame=sp mr.Velocity=Vector3.zero end kickLoopEnabled=false Toggles.GrabTrollToggle:SetValue(false) end) end})
TargetGroup:AddToggle("LoopKickToggle",{Text="Loop Kick (grab + blob)",Default=false,Callback=function(on) kickLoopEnabled=on local tg=selectedKickPlayer if on and not tg then if Toggles.LoopKickToggle then Toggles.LoopKickToggle:SetValue(false) end return end local c=Player.Character local hm=c and c:FindFirstChild("Humanoid") local se=hm and hm.SeatPart if on and(not se or se.Parent.Name~="CreatureBlobman") then if Toggles.LoopKickToggle then Toggles.LoopKickToggle:SetValue(false) end return end if not on then kickLoopEnabled=false return end task.spawn(function() local GE=RS:WaitForChild("GrabEvents") local bl=se.Parent local br=bl:FindFirstChild("HumanoidRootPart") or bl.PrimaryPart local so=bl:FindFirstChild("BlobmanSeatAndOwnerScript") local CG=so and so:FindFirstChild("CreatureGrab") local CD=so and so:FindFirstChild("CreatureDrop") local RD=bl:FindFirstChild("RightDetector") local RW=RD and(RD:FindFirstChild("RightWeld") or RD:FindFirstChildWhichIsA("Weld")) local SP=br.CFrame local tc=tg.Character local tr=tc and tc:FindFirstChild("HumanoidRootPart") if tr and br then local bs=tick() while tick()-bs<0.35 do if not kickLoopEnabled then break end br.CFrame=tr.CFrame br.Velocity=Vector3.zero pcall(function() if CG and RD then CG:FireServer(RD,tr,RW) end GE.CreateGrabLine:FireServer(tr,Vector3.zero,tr.Position,false) GE.SetNetworkOwner:FireServer(tr,br.CFrame) end) RunService.Heartbeat:Wait() end br.CFrame=SP br.Velocity=Vector3.zero task.wait(0.05) end local pt=0 while kickLoopEnabled do if not tg or not tg.Parent or not tg.Character then break end local tc=tg.Character local tr=tc and tc:FindFirstChild("HumanoidRootPart") local th=tc and tc:FindFirstChild("Humanoid") if tr and th and th.Health>0 and br then br.CFrame=SP br.Velocity=Vector3.zero local lp=SP*CFrame.new(0,23,0) tr.CFrame=lp tr.Velocity=Vector3.zero tr.RotVelocity=Vector3.zero if tick()-pt>0.05 then pt=tick() pcall(function() th.PlatformStand=true th.Sit=true GE.SetNetworkOwner:FireServer(tr,lp) if RD then local w=RD:FindFirstChild("RightWeld") or RD:FindFirstChildWhichIsA("Weld") if w then CD:FireServer(w) end end GE.DestroyGrabLine:FireServer(tr) if RD then CG:FireServer(RD,tr,RW) end GE.CreateGrabLine:FireServer(tr,Vector3.zero,tr.Position,false) end) end else br.CFrame=SP br.Velocity=Vector3.zero end if not kickLoopEnabled then break end RunService.Heartbeat:Wait() end kickLoopEnabled=false if Toggles.LoopKickToggle then Toggles.LoopKickToggle:SetValue(false) end if br then br.CFrame=SP br.Velocity=Vector3.zero end end) end})
local loopKickDualActive=false
TargetGroup:AddToggle("DualHandLoopKick",{Text="Loop Kick",Default=false,Callback=function(on) loopKickDualActive=on if on then if not selectedKickPlayer then notify("Error","Select target first",3) Toggles.DualHandLoopKick:SetValue(false) return end task.spawn(function() local lt=nil local bp=nil while loopKickDualActive do local tg=selectedKickPlayer local c=Player.Character local hm=c and c:FindFirstChild("Humanoid") local se=hm and hm.SeatPart if not se or not tg or not tg.Parent then task.wait(0.5) continue end local sp=se.Parent local gr=sp:FindFirstChild("BlobmanSeatAndOwnerScript") and sp.BlobmanSeatAndOwnerScript:FindFirstChild("CreatureGrab") local dr=sp:FindFirstChild("BlobmanSeatAndOwnerScript") and sp.BlobmanSeatAndOwnerScript:FindFirstChild("CreatureDrop") if not gr or not dr then task.wait(0.5) continue end local ld=sp:FindFirstChild("LeftDetector") local rd=sp:FindFirstChild("RightDetector") local lw=ld and ld:FindFirstChild("LeftWeld") local rw=rd and rd:FindFirstChild("RightWeld") local h=c:FindFirstChild("HumanoidRootPart") local tc=tg.Character local th=tc and tc:FindFirstChild("HumanoidRootPart") local tm=tc and tc:FindFirstChild("Humanoid") if th and tm and tm.Health>0 then if tc~=lt then lt=tc if bp then bp:Destroy() bp=nil end if h then h.CFrame=th.CFrame*CFrame.new(0,25,0) end task.wait(0.2) gr:FireServer(ld,th,lw) task.wait(0.3) dr:FireServer(lw,th) task.wait(0.1) bp=Instance.new("BodyPosition") bp.Position=Vector3.new(0,999999,0) bp.MaxForce=Vector3.new(math.huge,math.huge,math.huge) bp.Parent=th gr:FireServer(ld,th,lw) task.wait(0.2) dr:FireServer(lw,th) end gr:FireServer(ld,th,lw) task.wait() dr:FireServer(lw,th) task.wait() gr:FireServer(rd,th,rw) task.wait() dr:FireServer(rw,th) task.wait() gr:FireServer(ld,th,lw) gr:FireServer(rd,th,rw) task.wait() dr:FireServer(lw,th) dr:FireServer(rw,th) task.wait() else task.wait(0.1) end end if bp then bp:Destroy() end end) else loopKickDualActive=false end end})
local playerFlingActive=false local flingBAV=nil local originalPos=nil
TargetGroup:AddToggle("PlayerFlingBtn",{Text="Fling",Default=false,Callback=function(on) playerFlingActive=on if on then if not selectedKickPlayer then notify("System","Select target first!",3) Toggles.PlayerFlingBtn:SetValue(false) return end local MC=Player.Character local MR=MC and MC:FindFirstChild("HumanoidRootPart") if MR then originalPos=MR.CFrame end notify("Maestro","Fling Mode Activated.",3) task.spawn(function() while playerFlingActive do local tg=selectedKickPlayer local c=Player.Character local h=c and c:FindFirstChild("HumanoidRootPart") local hm=c and c:FindFirstChild("Humanoid") if not h or not hm then task.wait(0.5) continue end if tg and tg.Parent then local tc=tg.Character local tr=tc and tc:FindFirstChild("HumanoidRootPart") local tm=tc and tc:FindFirstChild("Humanoid") if tr and tm and tm.Health>0 then if not flingBAV or flingBAV.Parent~=h then if flingBAV then flingBAV:Destroy() end flingBAV=Instance.new("BodyAngularVelocity") flingBAV.Name="MaestroSpin" flingBAV.MaxTorque=Vector3.new(math.huge,math.huge,math.huge) flingBAV.AngularVelocity=Vector3.new(0,10000,0) flingBAV.P=10000 flingBAV.Parent=h end for _,p in pairs(c:GetDescendants()) do if p:IsA("BasePart") then p.CanCollide=false end end local lp=RunService.Heartbeat:Connect(function() if not playerFlingActive or not tr or not tr.Parent then return end h.CFrame=tr.CFrame h.Velocity=Vector3.zero end) local st=tick() while tick()-st<1.5 do if not playerFlingActive or not tr.Parent then break end task.wait(0.1) end if lp then lp:Disconnect() end else task.wait(0.2) end else playerFlingActive=false Toggles.PlayerFlingBtn:SetValue(false) end task.wait(0.1) end if flingBAV then flingBAV:Destroy() flingBAV=nil end local c=Player.Character if c then for _,p in pairs(c:GetDescendants()) do if p:IsA("BasePart") then p.CanCollide=true end end local h=c:FindFirstChild("HumanoidRootPart") if h then h.RotVelocity=Vector3.zero h.Velocity=Vector3.zero if originalPos then h.CFrame=originalPos end end end end) else playerFlingActive=false if flingBAV then flingBAV:Destroy() flingBAV=nil end local c=Player.Character local h=c and c:FindFirstChild("HumanoidRootPart") if h then h.RotVelocity=Vector3.zero h.Velocity=Vector3.zero end end end})
