local loopAllActive=false
TargetGroup:AddToggle("LoopAllToggle",{Text="Loop All",Default=false,Callback=function(on) loopAllActive=on if not on then return end task.spawn(function() local GE=RS:WaitForChild("GrabEvents") local mc=Player.Character or Player.CharacterAdded:Wait() local mr=mc:FindFirstChild("HumanoidRootPart") if not mr then Toggles.LoopAllToggle:SetValue(false) return end local sp=mr.CFrame while loopAllActive do mc=Player.Character mr=mc and mc:FindFirstChild("HumanoidRootPart") if not mr then break end for _,pl in ipairs(PS:GetPlayers()) do if not loopAllActive then break end if pl~=Player then local tc=pl.Character local tr=tc and tc:FindFirstChild("HumanoidRootPart") local th=tc and tc:FindFirstChild("Humanoid") if tr and th and th.Health>0 then pcall(function() mr.CFrame=tr.CFrame mr.Velocity=Vector3.zero th.PlatformStand=true th.Sit=true GE.SetNetworkOwner:FireServer(tr,mr.CFrame) GE.CreateGrabLine:FireServer(tr,Vector3.zero,tr.Position,false) end) task.wait(0.08) pcall(function() mr.CFrame=sp mr.Velocity=Vector3.zero local lp=sp*CFrame.new(0,17,0) tr.CFrame=lp tr.Velocity=Vector3.zero tr.RotVelocity=Vector3.zero th.PlatformStand=true th.Sit=false GE.SetNetworkOwner:FireServer(tr,lp) GE.DestroyGrabLine:FireServer(tr) GE.CreateGrabLine:FireServer(tr,Vector3.zero,tr.Position,false) end) task.wait(0.05) end end end RunService.Heartbeat:Wait() end if mr then mr.CFrame=sp mr.Velocity=Vector3.zero end loopAllActive=false Toggles.LoopAllToggle:SetValue(false) end) end})

UserInputService.InputBegan:Connect(function(i,p) if not p and i.KeyCode==Enum.KeyCode.T and _G.AutoSitBlobT then local pl=game.Players.LocalPlayer local c=pl.Character local h=c and c:FindFirstChild("HumanoidRootPart") local hm=c and c:FindFirstChild("Humanoid") if not h or not hm then return end local fn=pl.Name.."SpawnedInToys" local f=workspace:FindFirstChild(fn) local bl=f and f:FindFirstChild("CreatureBlobman") if not bl then task.spawn(function() pcall(function() game.ReplicatedStorage.MenuToys.SpawnToyRemoteFunction:InvokeServer("CreatureBlobman",h.CFrame,Vector3.zero) end) end) if not f then f=workspace:WaitForChild(fn,5) end if f then bl=f:WaitForChild("CreatureBlobman",5) end end if bl then local se=bl:WaitForChild("VehicleSeat",5) if se then local t=tick() repeat if not hm.SeatPart then h.CFrame=se.CFrame+Vector3.new(0,1,0) h.Velocity=Vector3.zero se:Sit(hm) end RunService.Heartbeat:Wait() until hm.SeatPart==se or tick()-t>1.5 end end end end)
UserInputService.InputBegan:Connect(function(i,gp) if not gp and i.KeyCode==Enum.KeyCode.R then if blobMasterSwitch then blobFlyActive=not blobFlyActive if not blobFlyActive then if bvInstance then bvInstance:Destroy() bvInstance=nil end if bgInstance then bgInstance:Destroy() bgInstance=nil end end end end end)
local function GetBlobRoot() local c=Player.Character local hm=c and c:FindFirstChild("Humanoid") if hm and hm.SeatPart and hm.SeatPart.Parent and hm.SeatPart.Parent.Name=="CreatureBlobman" then return hm.SeatPart.Parent:FindFirstChild("HumanoidRootPart") or hm.SeatPart.Parent.PrimaryPart end local f=workspace:FindFirstChild(Player.Name.."SpawnedInToys") if f then local bl=f:FindFirstChild("CreatureBlobman") if bl then return bl:FindFirstChild("HumanoidRootPart") or bl.PrimaryPart end end return nil end
RunService.Heartbeat:Connect(function() if not blobFlyActive or not blobMasterSwitch then if bvInstance then bvInstance:Destroy() bvInstance=nil end if bgInstance then bgInstance:Destroy() bgInstance=nil end return end local rt=GetBlobRoot() if rt then if not rt:FindFirstChild("BlobFlyVelocity") then bvInstance=Instance.new("BodyVelocity") bvInstance.Name="BlobFlyVelocity" bvInstance.MaxForce=Vector3.new(math.huge,math.huge,math.huge) bvInstance.P=10000 bvInstance.Parent=rt else bvInstance=rt.BlobFlyVelocity end if not rt:FindFirstChild("BlobFlyGyro") then bgInstance=Instance.new("BodyGyro") bgInstance.Name="BlobFlyGyro" bgInstance.MaxTorque=Vector3.new(math.huge,math.huge,math.huge) bgInstance.P=20000 bgInstance.D=100 bgInstance.Parent=rt else bgInstance=rt.BlobFlyGyro end local cm=workspace.CurrentCamera local md=Vector3.zero if UserInputService:IsKeyDown(Enum.KeyCode.W) then md=md+cm.CFrame.LookVector end if UserInputService:IsKeyDown(Enum.KeyCode.S) then md=md-cm.CFrame.LookVector end if UserInputService:IsKeyDown(Enum.KeyCode.A) then md=md-cm.CFrame.RightVector end if UserInputService:IsKeyDown(Enum.KeyCode.D) then md=md+cm.CFrame.RightVector end if UserInputService:IsKeyDown(Enum.KeyCode.Space) then md=md+Vector3.new(0,1,0) end if UserInputService:IsKeyDown(Enum.KeyCode.LeftControl) then md=md-Vector3.new(0,1,0) end if bvInstance then bvInstance.Velocity=md*blobFlySpeed end if bgInstance then bgInstance.CFrame=cm.CFrame end else if bvInstance then bvInstance:Destroy() bvInstance=nil end if bgInstance then bgInstance:Destroy() bgInstance=nil end end end)
local DestroyTargetGucciActive=false
TargetGroup:AddToggle("DestroyTargetGucci",{Text="Destroy Gucci (sit)",Default=false,Callback=function(V) DestroyTargetGucciActive=V if V then if not selectedKickPlayer then notify("Error","Error",3) Toggles.DestroyTargetGucci:SetValue(false) return end local c=Player.Character local rt=c and c:FindFirstChild("HumanoidRootPart") if not rt then return end local SS=rt.CFrame local fn=selectedKickPlayer.Name.."SpawnedInToys" notify("System","spawn toy "..fn,3) task.spawn(function() while DestroyTargetGucciActive do if not selectedKickPlayer or not selectedKickPlayer.Parent then DestroyTargetGucciActive=false Toggles.DestroyTargetGucci:SetValue(false) break end local tf=workspace:FindFirstChild(fn) if not tf then task.wait(1) else for _,o in ipairs(tf:GetChildren()) do if not DestroyTargetGucciActive then break end if o.Name=="CreatureBlobman" then local se=o:FindFirstChild("VehicleSeat") or o:FindFirstChildWhichIsA("VehicleSeat",true) if se then local mc=Player.Character local mr=mc and mc:FindFirstChild("HumanoidRootPart") local mh=mc and mc:FindFirstChild("Humanoid") if mr and mh and mh.SeatPart~=se then local mg=RunService.Stepped:Connect(function() if mr and se then mr.CFrame=se.CFrame mr.Velocity=Vector3.zero if o.PrimaryPart then o.PrimaryPart.Velocity=Vector3.zero o.PrimaryPart.RotVelocity=Vector3.zero end end end) local st=tick() while tick()-st<1 do if not DestroyTargetGucciActive or mh.SeatPart==se then break end se:Sit(mh) task.wait() end if mg then mg:Disconnect() end if mh.SeatPart==se then task.wait(0.3) mh.Sit=false mh.Jump=true task.wait(0.05) mr.CFrame=SS mr.Velocity=Vector3.zero notify("Success","gucci has removed",1) task.wait(0.5) else mr.CFrame=SS end end end end end end task.wait(1) end end) else DestroyTargetGucciActive=false notify("System","remove Gucci off",2) end end})
TargetGroup:AddButton({Text="bring",Func=function() if not selectedKickPlayer then return end local c=Player.Character local hm=c and c:FindFirstChild("Humanoid") local se=hm and hm.SeatPart if not se or se.Parent.Name~="CreatureBlobman" then return end local bl=se.Parent local br=bl:FindFirstChild("HumanoidRootPart") local so=bl:FindFirstChild("BlobmanSeatAndOwnerScript") if not br or not so then return end local CG=so:FindFirstChild("CreatureGrab") local CD=so:FindFirstChild("CreatureDrop") local RD=bl:FindFirstChild("RightDetector") local RW=RD and RD:FindFirstChild("RightWeld") local tc=selectedKickPlayer.Character local tr=tc and tc:FindFirstChild("HumanoidRootPart") if not tr then return end local hm2=br.CFrame br.CFrame=tr.CFrame br.Velocity=Vector3.new() br.RotVelocity=Vector3.new() task.wait(0.3) pcall(function() CG:FireServer(RD,tr,RW) end) task.wait(0.5) br.CFrame=hm2 br.Velocity=Vector3.new() br.RotVelocity=Vector3.new() task.wait(0.05) for i=1,12 do tr.CFrame=hm2*CFrame.new(0,3,0) tr.Velocity=Vector3.new() tr.RotVelocity=Vector3.new() task.wait(0.03) end for i=1,8 do local w=RD:FindFirstChild("RightWeld") if w then pcall(function() CD:FireServer(w) end) end task.wait(0.03) end end})
local AllowedItems={FoodHamburger=true,FoodCoconut=true,FoodPizzaCheese=true,FoodPizzaPepperoni=true,FoodHotdog=true,FoodMushroomPoison=true,FoodBread=true,FoodDippyEgg=true,FoodMayonnaise=true,FoodFrenchFries=true,FoodMeatStick=true,FoodDonut=true,FoodCakePink=true,InstrumentGuitarBanjo=true,InstrumentGuitarViolin=true,InstrumentGuitarUkulele=true,InstrumentWoodwindSaxophone=true,InstrumentWoodwindOcarina=true,InstrumentBrassVuvuzelaQwizik=true,InstrumentBrassTrumpet=true,InstrumentDrumBongos=true,InstrumentDrumSnare=true,InstrumentPianoMelodica=true,InstrumentVoiceMicrophone=true,CupMugWhite=true,CupMugBrown=true,PoopPile=true,PoopPileSparkle=true}
local antiAntiLagEnabled=false
TargetGroup:AddToggle("RemoveAntiInputLag",{Text="Remove Anti Input Lag",Default=false,Callback=function(on) antiAntiLagEnabled=on if not on then return end task.spawn(function() local p=game.Players.LocalPlayer local c=p.Character local h=c:FindFirstChild("HumanoidRootPart") if not h then return end local bg={} for _,v in ipairs(workspace:GetDescendants()) do if AllowedItems[v.Name] and v:IsA("Model") and v:FindFirstChild("HoldPart") then bg[#bg+1]=v end end workspace.DescendantAdded:Connect(function(o) if AllowedItems[o.Name] and o:IsA("Model") then task.spawn(function() local hp=o:WaitForChild("HoldPart",3) if hp then bg[#bg+1]=o end end) end end) while antiAntiLagEnabled do for i=#bg,1,-1 do local b=bg[i] if not b or not b.Parent or not b:FindFirstChild("HoldPart") then table.remove(bg,i) else local hp=b.HoldPart pcall(function() hp.HoldItemRemoteFunction:InvokeServer(b,c) end) task.wait() pcall(function() hp.DropItemRemoteFunction:InvokeServer(b,CFrame.new(h.Position+Vector3.new(0,-2000,0)),Vector3.new(0,0,0)) end) end end task.wait() end end) end})
