local espEnabled=false local espBoxes={} local targetNames={"partesp","playercharacterlocationdetector"}
local function IsTarget(o) if not o:IsA("BasePart") then return false end for _,n in ipairs(targetNames) do if string.lower(o.Name)==string.lower(n) then return true end end return false end
local function AddBoxESP(o) if espBoxes[o] then return end local b=Instance.new("BoxHandleAdornment") b.Adornee=o b.AlwaysOnTop=true b.ZIndex=5 b.Color3=Color3.fromRGB(255,255,255) b.Transparency=0.5 b.Size=o.Size b.Parent=CoreGui espBoxes[o]=b o.AncestryChanged:Connect(function(_,p) if not p and espBoxes[o] then espBoxes[o]:Destroy() espBoxes[o]=nil end end) end
local function RemoveAllBoxes() for o,b in pairs(espBoxes) do if b then b:Destroy() end end espBoxes={} end
local function Scan() for _,o in ipairs(workspace:GetDescendants()) do if espEnabled and IsTarget(o) then AddBoxESP(o) end end end
workspace.DescendantAdded:Connect(function(o) if espEnabled and IsTarget(o) then AddBoxESP(o) end end)
PlayerESP:AddToggle("BoxESPWhite",{Text="PCLD View",Default=false,Callback=function(V) espEnabled=V if espEnabled then Scan() else RemoveAllBoxes() end end})
PlayerESP:AddToggle("NicknameESP",{Text="Nickname Esp",Default=false,Callback=function(V) local function createESP(pl) if pl==Player then return end if pl.Character and pl.Character:FindFirstChild("HumanoidRootPart") then local h=pl.Character.HumanoidRootPart if h:FindFirstChild("NameESP") then return end local bb=Instance.new("BillboardGui") bb.Name="NameESP" bb.Adornee=h bb.Size=UDim2.new(0,100,0,30) bb.StudsOffset=Vector3.new(0,3,0) bb.AlwaysOnTop=true bb.Parent=h local tl=Instance.new("TextLabel") tl.Size=UDim2.new(1,0,1,0) tl.BackgroundTransparency=1 tl.Text=pl.Name tl.TextColor3=Color3.fromRGB(255,255,255) tl.TextStrokeTransparency=0 tl.TextScaled=true tl.Parent=bb end end if V then for _,pl in pairs(PS:GetPlayers()) do createESP(pl) pl.CharacterAdded:Connect(function() createESP(pl) end) end PS.PlayerAdded:Connect(function(pl) pl.CharacterAdded:Connect(function() createESP(pl) end) end) else for _,pl in pairs(PS:GetPlayers()) do if pl.Character and pl.Character:FindFirstChild("HumanoidRootPart") then local h=pl.Character.HumanoidRootPart if h:FindFirstChild("NameESP") then h.NameESP:Destroy() end end end end end})
