local MiscGroup=Tabs.Misc:AddLeftGroupbox("Miscellaneous") local mouse=Player:GetMouse()
MiscGroup:AddToggle("DreamyNightShaderToggle",{Text="Dreamy Night Shader",Default=false,Callback=function(on) local L=game:GetService("Lighting") if not _G.DreamyNightEffects then _G.DreamyNightOriginal={ClockTime=L.ClockTime,GlobalShadows=L.GlobalShadows,Brightness=L.Brightness,EnvironmentDiffuseScale=L.EnvironmentDiffuseScale,EnvironmentSpecularScale=L.EnvironmentSpecularScale,FogEnd=L.FogEnd} _G.DreamyNightEffects={} local B=Instance.new("BlurEffect") B.Size=6 B.Enabled=false B.Parent=L local Bl=Instance.new("BloomEffect") Bl.Intensity=1.6 Bl.Size=90 Bl.Threshold=1.4 Bl.Enabled=false Bl.Parent=L local C=Instance.new("ColorCorrectionEffect") C.Brightness=0.15 C.Contrast=-0.1 C.Saturation=0.25 C.TintColor=Color3.fromRGB(210,220,255) C.Enabled=false C.Parent=L local S=Instance.new("SunRaysEffect") S.Intensity=0.05 S.Spread=0.6 S.Enabled=false S.Parent=L local A=Instance.new("Atmosphere") A.Density=0.45 A.Offset=0.1 A.Color=Color3.fromRGB(180,190,255) A.Decay=Color3.fromRGB(120,130,180) A.Glare=0.15 A.Haze=3 A.Parent=L _G.DreamyNightEffects={B,Bl,C,S,A} end for _,e in ipairs(_G.DreamyNightEffects) do e.Enabled=on end if on then L.ClockTime=0.5 L.GlobalShadows=false L.Brightness=2 L.EnvironmentDiffuseScale=0.2 L.EnvironmentSpecularScale=0.1 L.FogEnd=200000 else local og=_G.DreamyNightOriginal if og then L.ClockTime=og.ClockTime L.GlobalShadows=og.GlobalShadows L.Brightness=og.Brightness L.EnvironmentDiffuseScale=og.EnvironmentDiffuseScale L.EnvironmentSpecularScale=og.EnvironmentSpecularScale L.FogEnd=og.FogEnd end end end})
local Triggerbot={Enabled=false,Connection=nil,canGrab=true,maxDistance=20,preGrabDelay=0.00001,postGrabDelay=0.05,lastTarget=nil,lastHitTime=0,targetMemoryDuration=0.1,checkThrottle=0.008,lastCheck=0}
local rayParams=RaycastParams.new() rayParams.FilterType=Enum.RaycastFilterType.Exclude
task.spawn(function() local s,r=pcall(function() return RS.GamepassEvents.CheckForGamepass:InvokeServer(20837132) end) if s and r then Triggerbot.maxDistance=29.3 end end)
if RS:FindFirstChild("GamepassEvents") and RS.GamepassEvents:FindFirstChild("FurtherReachBoughtNotifier") then RS.GamepassEvents.FurtherReachBoughtNotifier.OnClientEvent:Connect(function() Triggerbot.maxDistance=29.3 end) end
function Triggerbot:GetTarget() local c=Player.Character if not c or not c:FindFirstChild("HumanoidRootPart") then return end if Workspace:FindFirstChild("GrabParts") then return end local o,d=Camera.CFrame.Position,Camera.CFrame.LookVector rayParams.FilterDescendantsInstances={c,Workspace.Terrain} local r=Workspace:Raycast(o,d*1000,rayParams) if not r then local ds={d,(d+Vector3.new(0,0.075,0)).Unit,(d-Vector3.new(0,0.075,0)).Unit} for _,dd in ipairs(ds) do r=Workspace:Raycast(o,dd*1000,rayParams) if r then break end end end if not r then return end local h=r.Instance local m=h:FindFirstAncestorOfClass("Model") if not m or not m:FindFirstChildOfClass("Humanoid") or m==c then return end local hm=m:FindFirstChildOfClass("Humanoid") if hm.Health<=0 then return end local rt=m:FindFirstChild("HumanoidRootPart") if not rt then return end if(c.HumanoidRootPart.Position-rt.Position).Magnitude>self.maxDistance then return end return m end
function Triggerbot:OnHeartbeat() if not self.Enabled or not self.canGrab then return end if UserInputService:GetFocusedTextBox() then return end if tick()-self.lastCheck<self.checkThrottle then return end self.lastCheck=tick() local t=self:GetTarget() if t then self.lastTarget=t self.lastHitTime=tick() elseif self.lastTarget and tick()-self.lastHitTime>self.targetMemoryDuration then self.lastTarget=nil end local c=Player.Character local rt=self.lastTarget and self.lastTarget:FindFirstChild("HumanoidRootPart") if not(self.lastTarget and c and c:FindFirstChild("HumanoidRootPart") and rt) then return end if(c.HumanoidRootPart.Position-rt.Position).Magnitude>self.maxDistance then self.lastTarget=nil return end if self.lastTarget then self.canGrab=false task.spawn(function() task.wait(self.preGrabDelay) pcall(mouse1press) local t0=tick() repeat task.wait(0.02) until not Workspace:FindFirstChild("GrabParts") or tick()-t0>1.6 task.wait(self.postGrabDelay) self.canGrab=true self.lastTarget=nil end) end end
