local BuildGroup=Tabs.Build:AddLeftGroupbox("Build") local heartHighRun=false local heartConnection=nil local heartToy=nil
BuildGroup:AddToggle("HeartSparklerBuild",{Text="Heart",Default=false,Callback=function(V) heartHighRun=V if V then task.spawn(function() if not Player.Character then return end local h=Player.Character:FindFirstChild("HumanoidRootPart") if not h then return end pcall(function() RS.MenuToys.SpawnToyRemoteFunction:InvokeServer("FireworkSparkler",h.CFrame*CFrame.new(0,50,0),Vector3.zero) end) local f=workspace:WaitForChild(Player.Name.."SpawnedInToys",5) if not f then return end heartToy=f:WaitForChild("FireworkSparkler",5) if not heartToy then return end local p=heartToy:FindFirstChild("Handle") or heartToy:FindFirstChildWhichIsA("BasePart") if not p then return end task.wait(0.2) for _,v in ipairs(heartToy:GetDescendants()) do if v:IsA("BasePart") then v.Anchored=false v.CanCollide=false v.Massless=true end end p:BreakJoints() local bp=Instance.new("BodyPosition") bp.MaxForce=Vector3.new(math.huge,math.huge,math.huge) bp.P=20000 bp.D=500 bp.Parent=p local bg=Instance.new("BodyGyro") bg.MaxTorque=Vector3.new(math.huge,math.huge,math.huge) bg.P=3000 bg.CFrame=CFrame.new() bg.Parent=p local t=0 if heartConnection then heartConnection:Disconnect() end heartConnection=RunService.Heartbeat:Connect(function(dt) if not heartHighRun or not p or not p.Parent then if heartConnection then heartConnection:Disconnect() end if heartToy then pcall(function() heartToy:Destroy() end) end return end local ch=Player.Character and Player.Character:FindFirstChild("HumanoidRootPart") if not ch then return end pcall(function() RS.GrabEvents.SetNetworkOwner:FireServer(p,p.CFrame) end) t=t+(8*dt) local sc=1.5 local x=16*math.sin(t)^3 local y=13*math.cos(t)-5*math.cos(2*t)-2*math.cos(3*t)-math.cos(4*t) bp.Position=ch.CFrame:PointToWorldSpace(Vector3.new(x*sc,(y*sc)+25,3)) bg.CFrame=ch.CFrame end) end) else if heartConnection then heartConnection:Disconnect() heartConnection=nil end if heartToy then pcall(function() heartToy:Destroy() end) heartToy=nil end end end})
