AurasGroup:AddDropdown("RemoveAntiKickAuraRadiusDropdown",{Text="Anti Kick Aura Radius",Values={"10","12","14","16","18","20"},Default="15",Callback=function(v) removeAntiKickRadius=tonumber(v) end})
