AurasGroup:AddToggle("DualHandKickAura",{Text="Dual Hand Kick Aura",Default=false,Callback=function(on) dualKickAuraEnabled=on if dualKickAuraConn then dualKickAuraConn:Disconnect() dualKickAuraConn=nil end if not on then return end local tl=0 dualKickAuraConn=RunService.Heartbeat:Connect(function() if tick()-tl<0.12 then return end tl=tick() local mc=Player.Character local hm=mc and mc:FindFirstChildOfClass("Humanoid") local se=hm and hm.SeatPart local mr=mc and mc:FindFirstChild("HumanoidRootPart") if not(se and mr) then return end local sp=se.Parent local sf=sp and sp:FindFirstChild("BlobmanSeatAndOwnerScript") local gr=sf and sf:FindFirstChild("CreatureGrab") local dr=sf and sf:FindFirstChild("CreatureDrop") local ld=sp:FindFirstChild("LeftDetector") local rd=sp:FindFirstChild("RightDetector") local lw=ld and ld:FindFirstChild("LeftWeld") local rw=rd and rd:FindFirstChild("RightWeld") if not(gr and dr and ld and rd and lw and rw) then return end for _,pl in ipairs(PS:GetPlayers()) do if pl~=Player and pl.Character and canKick(pl) then local h=pl.Character:FindFirstChild("HumanoidRootPart") local hm2=pl.Character:FindFirstChildOfClass("Humanoid") if h and hm2 and hm2.Health>0 and(h.Position-mr.Position).Magnitude<=dualKickAuraRadius then pcall(function() gr:FireServer(ld,h,lw) task.wait(0.04) dr:FireServer(lw,h) gr:FireServer(rd,h,rw) task.wait(0.04) dr:FireServer(rw,h) gr:FireServer(ld,h,lw) gr:FireServer(rd,h,rw) task.wait(0.03) dr:FireServer(lw,h) dr:FireServer(rw,h) end) end end end end) end})
