AurasGroup:AddToggle("KickAura1Toggle",{Text="Kick Aura 1 Hand (grab + blob)",Default=false,Callback=function(on) kickAura1Enabled=on if kickAura1Conn then kickAura1Conn:Disconnect() kickAura1Conn=nil end if not on then return end kickAura1Conn=RunService.Heartbeat:Connect(function() local c=Player.Character local hm=c and c:FindFirstChild("Humanoid") local se=hm and hm.SeatPart local rt=c and c:FindFirstChild("HumanoidRootPart") if not(se and rt) then return end local bl=se.Parent local br=bl:FindFirstChild("HumanoidRootPart") or bl.PrimaryPart local so=bl:FindFirstChild("BlobmanSeatAndOwnerScript") local CG=so and so:FindFirstChild("CreatureGrab") local CD=so and so:FindFirstChild("CreatureDrop") local RD=bl:FindFirstChild("RightDetector") local RW=RD and(RD:FindFirstChild("RightWeld") or RD:FindFirstChildWhichIsA("Weld")) if not(CG and CD and RD and RW and br) then return end local pt=0 for _,pl in ipairs(PS:GetPlayers()) do if pl~=Player and pl.Character and(not kickAura1Whitelist or not Player:IsFriendsWith(pl.UserId)) then local tr=pl.Character:FindFirstChild("HumanoidRootPart") local th=pl.Character:FindFirstChild("Humanoid") if tr and th and th.Health>0 and(tr.Position-rt.Position).Magnitude<=kickAura1Radius then pcall(function() if tick()-pt>0.05 then pt=tick() local w=RD:FindFirstChild("RightWeld") or RD:FindFirstChildWhichIsA("Weld") if w then CD:FireServer(w) CG:FireServer(RD,tr,RW) end end end) end end end end) end})
