AurasGroup:AddToggle("KillAuraToggle",{Text="Kill Aura",Default=false,Callback=function(on) killAuraEnabled=on if killAuraConn then killAuraConn:Disconnect() killAuraConn=nil end if not on then return end killAuraConn=RunService.Heartbeat:Connect(function() local mc=Player.Character local mr=mc and mc:FindFirstChild("HumanoidRootPart") if not mr then return end if Workspace:FindFirstChild("GrabParts") then return end for _,pl in ipairs(PS:GetPlayers()) do if pl~=Player and pl.Character then if killAuraWhitelist and Player:IsFriendsWith(pl.UserId) then continue end local tr=pl.Character:FindFirstChild("HumanoidRootPart") local th=pl.Character:FindFirstChildOfClass("Humanoid") if tr and th and th.Health>0 and(tr.Position-mr.Position).Magnitude<=killAuraRadius then pcall(function() local dist=(tr.Position-mr.Position) local dir=dist.Unit mr.CFrame=CFrame.new(tr.Position-dir*3,tr.Position) pcall(mouse1press) task.defer(function() task.wait(0.05) local gp=Workspace:FindFirstChild("GrabParts") if gp then local g=gp:FindFirstChild("GrabPart") if g and g:FindFirstChild("WeldConstraint") then local p1=g.WeldConstraint.Part1 if p1 and p1.Parent and p1.Parent~=mc then local tc2=p1.Parent local th2=tc2:FindFirstChildOfClass("Humanoid") if th2 then th2.Health=0 tc2:BreakJoints() end end end end pcall(mouse1release) end) end) return end end end end) end})
--MEGA ANTI Tab - Anti All [Owner Mehanik 2025] (Pro Version Anti All copy)
local ProAntiAllEnabled2=false local ProAntiAllConnections2={} local SAFE_POSITION2=CFrame.new(322.31,9.52,489.68)
local function getChar2() return Player.Character end local function getHum2() local c=getChar2() return c and c:FindFirstChildOfClass("Humanoid") end local function getHRP2() local c=getChar2() return c and c:FindFirstChild("HumanoidRootPart") end
MegaAntiGroup:AddToggle("ProAntiAll2",{Text="Anti All [Owner Mehanik 2025]",Default=false,Callback=function(V) ProAntiAllEnabled2=V if V then for _,cn in pairs(ProAntiAllConnections2) do pcall(function() cn:Disconnect() end) end ProAntiAllConnections2={} local function ultraLock() if not ProAntiAllEnabled2 then return end local hrp=getHRP2() local hum=getHum2() local char=getChar2() if not hrp or not char then return end for _i=1,1000 do hrp.CFrame=SAFE_POSITION2 hrp.AssemblyLinearVelocity=Vector3.zero hrp.AssemblyAngularVelocity=Vector3.zero end hrp.Anchored=true hrp.CFrame=SAFE_POSITION2 for _,child in pairs(hrp:GetChildren()) do if child:IsA("BodyVelocity") or child:IsA("BodyForce") or child:IsA("BodyThrust") or child:IsA("BodyAngularVelocity") or child:IsA("BodyPosition") or child:IsA("BodyGyro") or child:IsA("LinearVelocity") or child:IsA("VectorForce") or child:IsA("AlignPosition") or child:IsA("AlignOrientation") or child:IsA("LineForce") then child:Destroy() end end for _,part in pairs(char:GetDescendants()) do if part:IsA("BasePart") then part.AssemblyLinearVelocity=Vector3.zero part.AssemblyAngularVelocity=Vector3.zero part.Massless=true for _,child in pairs(part:GetChildren()) do if child:IsA("BodyVelocity") or child:IsA("BodyForce") or child:IsA("BodyThrust") or child:IsA("BodyAngularVelocity") or child:IsA("LinearVelocity") or child:IsA("VectorForce") or child:IsA("AlignPosition") or child:IsA("AlignOrientation") then child:Destroy() end end end end for _,v in pairs(char:GetDescendants()) do if(v:IsA("Weld") or v:IsA("WeldConstraint") or v:IsA("RigidConstraint") or v:IsA("BallSocketConstraint") or v:IsA("HingeConstraint") or v:IsA("RopeConstraint") or v:IsA("SpringConstraint") or v:IsA("RodConstraint")) and v.Part0 and v.Part1 then if not v.Part0:IsDescendantOf(char) or not v.Part1:IsDescendantOf(char) then v:Destroy() end end end if hum and hum.SeatPart and not hum.SeatPart:IsDescendantOf(char) then hum.Jump=true end if hum then hum.PlatformStand=false hum.Health=hum.MaxHealth end for _,v in pairs(char:GetDescendants()) do if v:IsA("Fire") or v:IsA("Smoke") or v:IsA("Sparkles") then v:Destroy() end end pcall(function() if hum then local animator=hum:FindFirstChildOfClass("Animator") if animator then for _,track in pairs(animator:GetPlayingAnimationTracks()) do local an="" pcall(function() an=track.Animation and track.Animation.Name or"" end) local ln=string.lower(an) local safe=false for _,s in ipairs({"idle","walk","run","jump","fall","climb","sit","swim"}) do if string.find(ln,s) then safe=true break end end if not safe then track:Stop(0) end end end end end) hrp.AssemblyLinearVelocity=Vector3.zero hrp.AssemblyAngularVelocity=Vector3.zero hrp.CFrame=SAFE_POSITION2 hrp.Anchored=true end table.insert(ProAntiAllConnections2,RunService.RenderStepped:Connect(ultraLock)) table.insert(ProAntiAllConnections2,RunService.Heartbeat:Connect(ultraLock)) table.insert(ProAntiAllConnections2,RunService.Stepped:Connect(function() ultraLock() end)) notify("Anti All","IMMOVABLE ACTIVATED! 1000x TP x 3 threads",5) else for _,cn in pairs(ProAntiAllConnections2) do pcall(function() cn:Disconnect() end) end ProAntiAllConnections2={} pcall(function() local hrp=getHRP2() if hrp then hrp.Anchored=false end local char=getChar2() if char then for _,part in pairs(char:GetDescendants()) do if part:IsA("BasePart") then part.Massless=false end end end end) notify("Anti All","Disabled. Anchor removed.",3) end end})
--Fun Tab
local FanAnimGroup=Tabs.Fun:AddLeftGroupbox("Animations") local FanTrollGroup=Tabs.Fun:AddLeftGroupbox("Troll")
local animEnabled=false local currentTrack=nil local selectedAnimName="Crazy" local selectedAnimKey=Enum.KeyCode.Q
local Animations={["Crazy"]="rbxassetid://248263260",["Insane"]="rbxassetid://35654637",["Collapse"]="rbxassetid://35154961",["Zombie"]="rbxassetid://33796059"}
local function playAnimation() local c=Player.Character or Player.CharacterAdded:Wait() local hm=c:FindFirstChildOfClass("Humanoid") if not hm then return end local an=hm:FindFirstChildOfClass("Animator") if not an then an=Instance.new("Animator") an.Parent=hm end if currentTrack then currentTrack:Stop() currentTrack=nil end local a=Instance.new("Animation") a.AnimationId=Animations[selectedAnimName] currentTrack=an:LoadAnimation(a) currentTrack.Priority=Enum.AnimationPriority.Action currentTrack.Looped=true currentTrack:Play() task.spawn(function() while animEnabled and currentTrack do if currentTrack.TimePosition>0.9 then currentTrack.TimePosition=0.3 end task.wait(0.05) end end) end
local function stopAnimation() if currentTrack then currentTrack:Stop() currentTrack=nil end end
FanAnimGroup:AddToggle("AnimToggle",{Text="Play Animation",Default=false,Callback=function(on) animEnabled=on if on then playAnimation() else stopAnimation() end end})
FanAnimGroup:AddDropdown("AnimSelect",{Text="Animation",Values={"Crazy","Insane","Collapse","Zombie"},Default=1,Callback=function(v) selectedAnimName=v if animEnabled then playAnimation() end end})
FanAnimGroup:AddDropdown("AnimKeybind",{Text="Toggle Key",Values={"Q","E","R","T","F","Z","X","C"},Default=1,Callback=function(v) selectedAnimKey=Enum.KeyCode[v] end})
local playJerkOffActive=false local jerkOffAnimTrack=nil local jerkOffAnimId="rbxassetid://168268306" local jerkKey=Enum.KeyCode.Q
local function startJerkOff() local c=Player.Character or Player.CharacterAdded:Wait() local hm=c:FindFirstChildOfClass("Humanoid") if not hm then return end local an=hm:FindFirstChildOfClass("Animator") if not an then an=Instance.new("Animator") an.Parent=hm end local a=Instance.new("Animation") a.AnimationId=jerkOffAnimId jerkOffAnimTrack=an:LoadAnimation(a) jerkOffAnimTrack.Priority=Enum.AnimationPriority.Action jerkOffAnimTrack:Play() task.spawn(function() while playJerkOffActive do task.wait(0.1) if jerkOffAnimTrack and jerkOffAnimTrack.IsPlaying then jerkOffAnimTrack.TimePosition=0.3 end end end) end
local function stopJerkOff() if jerkOffAnimTrack then jerkOffAnimTrack:Stop() jerkOffAnimTrack=nil end end
FanTrollGroup:AddToggle("JerkOffToggle",{Text="Jerk Off",Default=false,Callback=function(on) playJerkOffActive=on if on then startJerkOff() else stopJerkOff() end end})
FanTrollGroup:AddDropdown("JerkKey",{Text="Toggle Key",Values={"Q","E","R","T"},Default=1,Callback=function(v) jerkKey=Enum.KeyCode[v] end})
UserInputService.InputBegan:Connect(function(i,gp) if gp then return end if i.KeyCode==jerkKey then playJerkOffActive=not playJerkOffActive if playJerkOffActive then startJerkOff() else stopJerkOff() end end end)
local playBangActive=false local bangAnimTrack=nil local bangAnimId="rbxassetid://148840371" local bangSpeed=10
local function startBang() local c=Player.Character or Player.CharacterAdded:Wait() local hm=c:FindFirstChildOfClass("Humanoid") if not hm then return end local an=hm:FindFirstChildOfClass("Animator") if not an then an=Instance.new("Animator") an.Parent=hm end local a=Instance.new("Animation") a.AnimationId=bangAnimId bangAnimTrack=an:LoadAnimation(a) bangAnimTrack.Priority=Enum.AnimationPriority.Action bangAnimTrack:Play() bangAnimTrack:AdjustSpeed(bangSpeed) task.spawn(function() while playBangActive do task.wait(0.1) if bangAnimTrack and bangAnimTrack.IsPlaying then bangAnimTrack.TimePosition=0.1 end end end) end
local function stopBang() if bangAnimTrack then bangAnimTrack:Stop() bangAnimTrack=nil end end
FanTrollGroup:AddToggle("BangToggle",{Text="Bang (Slow)",Default=false,Callback=function(on) playBangActive=on if on then startBang() else stopBang() end end})
FanTrollGroup:AddToggle("FollowStare",{Text="Follow & Stare",Default=false,Callback=function(on) follow=on task.spawn(function() while follow do local tg=PS:GetPlayers()[math.random(#PS:GetPlayers())] if tg~=Player and tg.Character and tg.Character:FindFirstChild("HumanoidRootPart") then local h=Player.Character.HumanoidRootPart local th=tg.Character.HumanoidRootPart h.CFrame=CFrame.new(th.Position+th.CFrame.LookVector*-2,th.Position) end task.wait(0.3) end end) end})
FanTrollGroup:AddToggle("FakeDeathToggle",{Text="Fake Death",Default=false,Callback=function(on) local c=Player.Character if not c then return end local hm=c:FindFirstChildOfClass("Humanoid") if not hm then return end if on then hm:ChangeState(Enum.HumanoidStateType.Physics) hm.PlatformStand=true else hm.PlatformStand=false hm:ChangeState(Enum.HumanoidStateType.GettingUp) end end})
local fakeLagConn
FanTrollGroup:AddToggle("FakeLagToggle",{Text="Fake Lag",Default=false,Callback=function(on) if fakeLagConn then fakeLagConn:Disconnect() fakeLagConn=nil end if not on then return end fakeLagConn=RunService.Heartbeat:Connect(function() local rt=Player.Character and Player.Character:FindFirstChild("HumanoidRootPart") if not rt then return end if math.random(1,5)==1 then rt.CFrame=rt.CFrame*CFrame.new(math.random(-2,2)/10,0,math.random(-2,2)/10) end end) end})
FanTrollGroup:AddToggle("UFOShurikenStick",{Text="Stick Shuriken to UFO",Default=false,Callback=function(st) if not st then return end local SE=RS:WaitForChild("PlayerEvents"):WaitForChild("StickyPartEvent") local SR=RS.MenuToys:WaitForChild("SpawnToyRemoteFunction") local CS=Player:WaitForChild("CanSpawnToy") local TF=workspace:WaitForChild(Player.Name.."SpawnedInToys") local UFOs={workspace.Map.AlwaysHereTweenedObjects:FindFirstChild("InnerUFO"),workspace.Map.AlwaysHereTweenedObjects:FindFirstChild("OuterUFO")} local function gH() if Player.Character and Player.Character:FindFirstChild("HumanoidRootPart") then return Player.Character.HumanoidRootPart end return Player.CharacterAdded:Wait():WaitForChild("HumanoidRootPart") end task.spawn(function() for i=1,12 do local t=tick() while not CS.Value do if tick()-t>5 then break end task.wait(0.1) end local h=gH() if h then pcall(function() SR:InvokeServer("NinjaShuriken",h.CFrame*CFrame.new(0,10,15),Vector3.new()) end) end task.wait(0.15) end task.wait(1) for _,T in ipairs(TF:GetChildren()) do if T.Name=="NinjaShuriken" and T:FindFirstChild("StickyPart") then for _,U in ipairs(UFOs) do if U and U:FindFirstChild("Object") and U.Object:FindFirstChild("ObjectModel") and U.Object.ObjectModel:FindFirstChild("Body") then SE:FireServer(T.StickyPart,U.Object.ObjectModel.Body,CFrame.new()) local fw=U.Object:FindFirstChild("FollowThisPart") if fw then if fw:FindFirstChild("AlignOrientation") then fw.AlignOrientation.Enabled=false end if fw:FindFirstChild("AlignPosition") then fw.AlignPosition.Enabled=false end end end end end end end) end})
local function getNearestBlobman(md) local c=Player.Character local h=c and c:FindFirstChild("HumanoidRootPart") if not h then return end local n,d=nil,md or 50 for _,m in ipairs(workspace:GetDescendants()) do if m:IsA("Model") and m.Name=="CreatureBlobman" then local rt=m:FindFirstChild("HumanoidRootPart") or m.PrimaryPart if rt then local dd=(rt.Position-h.Position).Magnitude if dd<d then d=dd n=m end end end end return n end
local function SitOnBlobman() local c=Player.Character if not c then return end local hm=c:FindFirstChildOfClass("Humanoid") local h=c:FindFirstChild("HumanoidRootPart") if not hm or not h or hm.SeatPart then return end local bl=getNearestBlobman(40) if not bl then return end local se=bl:FindFirstChildWhichIsA("Seat",true) or bl:FindFirstChildWhichIsA("VehicleSeat",true) if not se then return end h.CFrame=se.CFrame*CFrame.new(0,1.2,-1) task.wait(0.05) pcall(function() se:Sit(hm) end) end
KeybindsGroup:AddLabel("Blobman"):AddKeyPicker("SitBlobmanKey",{Default="Z",Text="Sit on nearest Blobman",NoUI=false,Callback=function() SitOnBlobman() end})
--Sit Button on screen (black)
local sitBtn=Instance.new("TextButton") sitBtn.Name="SitButton" sitBtn.Size=UDim2.new(0,80,0,40) sitBtn.Position=UDim2.new(0,10,0.5,-20) sitBtn.BackgroundColor3=Color3.fromRGB(0,0,0) sitBtn.TextColor3=Color3.fromRGB(255,255,255) sitBtn.Text="Sit" sitBtn.Font=Enum.Font.GothamBold sitBtn.TextSize=18 sitBtn.BorderSizePixel=0 sitBtn.Parent=CoreGui local sitCorner=Instance.new("UICorner") sitCorner.CornerRadius=UDim.new(0,8) sitCorner.Parent=sitBtn sitBtn.MouseButton1Click:Connect(function() local pl=game.Players.LocalPlayer local c=pl.Character local h=c and c:FindFirstChild("HumanoidRootPart") local hm=c and c:FindFirstChild("Humanoid") if not h or not hm then return end local fn=pl.Name.."SpawnedInToys" local f=workspace:FindFirstChild(fn) local bl=f and f:FindFirstChild("CreatureBlobman") if not bl then task.spawn(function() pcall(function() game.ReplicatedStorage.MenuToys.SpawnToyRemoteFunction:InvokeServer("CreatureBlobman",h.CFrame,Vector3.zero) end) end) if not f then f=workspace:WaitForChild(fn,5) end if f then bl=f:WaitForChild("CreatureBlobman",5) end end if bl then local se=bl:WaitForChild("VehicleSeat",5) if se then local t=tick() repeat if not hm.SeatPart then h.CFrame=se.CFrame+Vector3.new(0,1,0) h.Velocity=Vector3.zero se:Sit(hm) end RunService.Heartbeat:Wait() until hm.SeatPart==se or tick()-t>1.5 end end end)
--Make sit button draggable
local dragging,dragInput,dragStart,startPos
sitBtn.InputBegan:Connect(function(i) if i.UserInputType==Enum.UserInputType.MouseButton1 or i.UserInputType==Enum.UserInputType.Touch then dragging=true dragStart=i.Position startPos=sitBtn.Position i.Changed:Connect(function() if i.UserInputState==Enum.UserInputState.End then dragging=false end end) end end)
sitBtn.InputChanged:Connect(function(i) if i.UserInputType==Enum.UserInputType.MouseMovement or i.UserInputType==Enum.UserInputType.Touch then dragInput=i end end)
UserInputService.InputChanged:Connect(function(i) if i==dragInput and dragging then local delta=i.Position-dragStart sitBtn.Position=UDim2.new(startPos.X.Scale,startPos.X.Offset+delta.X,startPos.Y.Scale,startPos.Y.Offset+delta.Y) end end)

local function playKickSound() local s=Instance.new("Sound") s.SoundId="rbxassetid://79150789336480" s.Volume=5 s.PlayOnRemove=true s.Parent=game:GetService("SoundService") s:Destroy() end
local function notifyKick(dn,un) Library:Notify({Title="GGOG Script 0.0.4 Alpha",Description=dn.." ("..un..") has been kicked",Time=6}) end
local function getClosestPlayer(pos) local cp,cd=nil,math.huge for _,pl in ipairs(PS:GetPlayers()) do if pl~=Player and pl.Character then local h=pl.Character:FindFirstChild("HumanoidRootPart") if h then local d=(h.Position-pos).Magnitude if d<cd then cd=d cp=pl end end end end return cp end
Workspace.ChildAdded:Connect(function(o) if o.Name=="BlackHoleKick" or o.Name=="BlackHoleDetected" then task.wait(0.05) local pos if o:IsA("BasePart") then pos=o.Position elseif o:IsA("Model") and o.PrimaryPart then pos=o.PrimaryPart.Position end if not pos then return end local pl=getClosestPlayer(pos) if not pl then return end playKickSound() notifyKick(pl.DisplayName,pl.Name) end end)
PS.PlayerAdded:Connect(function(pl) if pl:IsFriendsWith(Player.UserId) then notify("Notify friend",pl.Name.." joined",5) end end)
